############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.119) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "contextCurrency.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $name = randomPerson(); $rate = random(4,8,0.01); Context("Currency")->flags->set( trimTrailingZeros => 1, tolType => 'absolute', tolerance => 0.5 ); $speed = Currency("$rate"); $initial = random(300,400,0.25); $start = Currency("$initial"); $final = random(600,800,5); $end = Currency("$final"); $solution = ($final - $initial)/$rate; $weeks = {newUnit => {name => 'weeks', conversion => {factor => 60*60*24*7, s => 1}}}; $time = NumberWithUnits("$solution weeks", $weeks);
############################################################ # Body ############################################################
BEGIN_PGML To save up for a new phone that costs [`[$end]\text{,}`] [$name] sets aside 1% of [$name->possessive] pay each week. This works out to [`[$speed]`] per week. At present, [$name->subject] [$name->have] [`[$start]`] saved up. How long will it be until [$name] has saved up enough?
[_]{$time}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
